/**
 * Geolocation data extracted from CDN/proxy headers.
 */
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

/**
 * Mapping of common ISO 3166-1 alpha-2 country codes to country names.
 */
const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

function safeDecodeURIComponent(value: string): string {
  try {
    return decodeURIComponent(value)
  } catch {
    return value
  }
}

function toRad(deg: number): number {
  return (deg * Math.PI) / 180
}

/**
 * Extract geolocation data from raw `Headers`.
 *
 * Reads Vercel CDN headers (`x-vercel-ip-*`) with a Cloudflare
 * (`cf-ipcountry`) fallback for the country code.
 */
export function geoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()] || undefined
    : undefined

  return {
    city: city ? safeDecodeURIComponent(city) : undefined,
    country,
    countryCode,
    region,
    latitude,
    longitude,
    timezone,
  }
}

/**
 * Extract geolocation data from a request-like object that has a
 * `headers` property (e.g. `NextRequest`).
 */
export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

/**
 * Check whether the given `Geo` object's `countryCode` is contained in the
 * provided list of region / country codes.  Comparison is case-insensitive.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) {
    return false
  }
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

/**
 * Calculate the great-circle distance between two points on Earth using the
 * Haversine formula.  Coordinates are passed as strings (as they arrive from
 * HTTP headers) and the result is in **kilometres**.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const lat1Num = parseFloat(lat1)
  const lon1Num = parseFloat(lon1)
  const lat2Num = parseFloat(lat2)
  const lon2Num = parseFloat(lon2)

  const R = 6371 // Earth's mean radius in km
  const dLat = toRad(lat2Num - lat1Num)
  const dLon = toRad(lon2Num - lon1Num)
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1Num)) *
      Math.cos(toRad(lat2Num)) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}

